PRAGMA foreign_keys = ON;

ALTER TABLE users ADD COLUMN modules TEXT NOT NULL DEFAULT 'jornadas';
UPDATE users SET modules = 'jornadas,podcast' WHERE role = 'admin';

CREATE TABLE IF NOT EXISTS podcast_episodes (id TEXT PRIMARY KEY, episode_label TEXT NOT NULL, topic TEXT NOT NULL, guest TEXT NOT NULL DEFAULT '', recording_date TEXT, recording_status TEXT NOT NULL DEFAULT 'Pendiente', editing_status TEXT NOT NULL DEFAULT 'Pendiente', publication_status TEXT NOT NULL DEFAULT 'Pendiente', social_status TEXT NOT NULL DEFAULT 'Pendiente', press_status TEXT NOT NULL DEFAULT 'Pendiente', logos TEXT NOT NULL DEFAULT '', responsible TEXT NOT NULL DEFAULT '', cancelled INTEGER NOT NULL CHECK (cancelled IN (0, 1)) DEFAULT 0, cancel_reason TEXT NOT NULL DEFAULT '', source_order INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS podcast_schedule (id TEXT PRIMARY KEY, month TEXT NOT NULL DEFAULT '', episode_number TEXT NOT NULL DEFAULT '', week_label TEXT NOT NULL, action TEXT NOT NULL DEFAULT '', responsible TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'Pendiente', sort_order INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE INDEX IF NOT EXISTS idx_podcast_episodes_cancelled ON podcast_episodes(cancelled);
CREATE INDEX IF NOT EXISTS idx_podcast_episodes_date ON podcast_episodes(recording_date);
CREATE INDEX IF NOT EXISTS idx_podcast_schedule_order ON podcast_schedule(sort_order);

